SELECT s.*, cd_st.code_label AS site_type_cd_nm, cd_ss.code_label AS site_status_cd_nm FROM sy_site s LEFT JOIN sy_code cd_st ON cd_st.code_grp = 'SITE_TYPE' AND cd_st.code_value = s.site_type_cd LEFT JOIN sy_code cd_ss ON cd_ss.code_grp = 'SITE_STATUS' AND cd_ss.code_value = s.site_status_cd
ORDER BY s.site_id ASC ORDER BY s.site_id DESC ORDER BY s.site_nm ASC ORDER BY s.site_nm DESC ORDER BY s.reg_date ASC ORDER BY s.reg_date DESC ORDER BY s.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

