site_code = #{siteCode}, site_type_cd = #{siteTypeCd}, site_nm = #{siteNm}, site_domain = #{siteDomain}, logo_url = #{logoUrl}, favicon_url = #{faviconUrl}, site_desc = #{siteDesc}, site_email = #{siteEmail}, site_phone = #{sitePhone}, site_zip_code = #{siteZipCode}, site_address = #{siteAddress}, site_business_no = #{siteBusinessNo}, site_ceo = #{siteCeo}, site_status_cd = #{siteStatusCd}, config_json = #{configJson}, upd_by = #{updBy}, upd_date = #{updDate}, disp_path = #{dispPath},
